"use client";

import * as React from "react";
import { motion, useInView } from "motion/react";
import { cva, type VariantProps } from "class-variance-authority";

import { cn } from "@/lib/utils";

// =============================================================================
// TYPES
// =============================================================================

interface ShimmeringTextAudioProps extends VariantProps<
  typeof shimmerVariants
> {
  /** The text to display with shimmer effect */
  text: string;
  /** Speed multiplier for the shimmer animation. Default: 1 */
  speed?: number;
  /** Color of the shimmer highlight. Default: uses primary-foreground */
  shimmerColor?: string;
  /** Whether to trigger only when in viewport. Default: true */
  triggerOnView?: boolean;
  /** Additional class names */
  className?: string;
  /** Additional inline styles */
  style?: React.CSSProperties;
}

// =============================================================================
// VARIANTS
// =============================================================================

const shimmerVariants = cva("inline-block", {
  variants: {
    size: {
      sm: "text-sm",
      md: "text-base",
      lg: "text-lg",
      xl: "text-2xl",
    },
  },
  defaultVariants: {
    size: "md",
  },
});

// =============================================================================
// COMPONENT
// =============================================================================

function ShimmeringTextAudio({
  text,
  speed = 1,
  shimmerColor,
  triggerOnView = true,
  size,
  className,
  style,
}: ShimmeringTextAudioProps) {
  const ref = React.useRef<HTMLDivElement>(null);
  const isInView = useInView(ref, { once: true, amount: 0.5 });

  const shouldAnimate = triggerOnView ? isInView : true;

  const shimmerHighlight =
    shimmerColor || "var(--color-primary-foreground, #fff)";

  return (
    <motion.div
      ref={ref}
      data-slot="shimmering-text-audio"
      className={cn(shimmerVariants({ size }), className)}
      style={{
        backgroundImage: shouldAnimate
          ? `linear-gradient(
              90deg,
              currentColor 0%,
              currentColor 35%,
              ${shimmerHighlight} 50%,
              currentColor 65%,
              currentColor 100%
            )`
          : undefined,
        backgroundSize: "200% 100%",
        WebkitBackgroundClip: "text",
        backgroundClip: "text",
        WebkitTextFillColor: shouldAnimate ? "transparent" : undefined,
        color: shouldAnimate ? "transparent" : undefined,
        ...style,
      }}
      animate={
        shouldAnimate
          ? {
              backgroundPosition: ["100% 0%", "-100% 0%"],
            }
          : undefined
      }
      transition={{
        duration: 2.5 / speed,
        repeat: Infinity,
        ease: "linear",
      }}
    >
      {text}
    </motion.div>
  );
}

ShimmeringTextAudio.displayName = "ShimmeringTextAudio";

export { ShimmeringTextAudio, shimmerVariants };
export type { ShimmeringTextAudioProps };
